import React, {useState, useEffect} from "react";
import "./timelistCSS.css";
import {  } from "react-router-dom";

const TimeList = () => {
    var showTimes = {
        '01': {
            year: "2023",
            month: "11",
            day: "20",
            week: "一",
        },
        '02': {
            year: "2023",
            month: "11",
            day: "21",
            week: "二",
        },
        '03': {
            year: "2023",
            month: "11",
            day: "22",
            week: "三",
        },
    }

    return(
        <div className="versionANDtheater">
            <h3>{showTimes.year}年{showTimes.month}月{showTimes.day}日 星期{showTimes.week}</h3>
        </div>
    );
}

export default TimeList;
